@tailwind base;
@tailwind components;
@tailwind utilities;

/* Dark Mode Configuration */
@layer base {
  :root {
    color-scheme: light;
  }

  html.dark {
    color-scheme: dark;
  }
}

/* Custom Styles */
@layer components {
  .btn-primary {
    @apply bg-blue-600 hover:bg-blue-700 dark:bg-blue-700 dark:hover:bg-blue-600 text-white font-semibold py-2 px-4 sm:py-3 sm:px-8 rounded-lg transition duration-300 ease-in-out transform hover:scale-105 text-sm sm:text-base;
  }

  .btn-secondary {
    @apply bg-gray-600 hover:bg-gray-700 dark:bg-gray-700 dark:hover:bg-gray-600 text-white font-semibold py-2 px-4 sm:py-3 sm:px-8 rounded-lg transition duration-300 ease-in-out text-sm sm:text-base;
  }

  .input-field {
    @apply w-full px-3 py-2 sm:px-4 sm:py-3 border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-800 text-gray-900 dark:text-white rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 dark:focus:ring-blue-400 focus:border-transparent text-sm sm:text-base;
  }

  .card {
    @apply bg-white dark:bg-gray-800 rounded-lg shadow-lg p-4 sm:p-6 transition-colors duration-300;
  }

  .sidebar-link {
    @apply flex items-center px-4 py-3 text-gray-700 dark:text-gray-300 hover:bg-blue-50 dark:hover:bg-blue-900 dark:hover:bg-opacity-30 hover:text-blue-600 dark:hover:text-blue-400 transition duration-200 cursor-pointer rounded-lg text-sm sm:text-base;
  }

  .sidebar-link.active {
    @apply bg-blue-100 dark:bg-blue-900 dark:bg-opacity-40 text-blue-700 dark:text-blue-300 font-semibold;
  }
}

/* Background Slideshow */
.slideshow-container {
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  z-index: -1;
}

.slideshow-image {
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  object-fit: cover;
  opacity: 0;
  transition: opacity 2s ease-in-out;
}

.slideshow-image.active {
  opacity: 1;
}

.overlay {
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  background-color: rgba(30, 58, 138, 0.75);
  z-index: 0;
}

/* Sidebar Styles */
.sidebar {
  transition: width 0.3s ease, transform 0.3s ease;
}

.sidebar.collapsed {
  width: 80px;
}

.sidebar.expanded {
  width: 280px;
}

.sidebar-text {
  opacity: 1;
  transition: opacity 0.3s ease;
}

.sidebar.collapsed .sidebar-text {
  opacity: 0;
  width: 0;
  overflow: hidden;
}

/* Center icons when sidebar is collapsed */
.sidebar.collapsed .sidebar-link {
  @apply justify-center px-0;
}

/* Reduce profile box width when collapsed */
.sidebar.collapsed > div:nth-child(2) {
  padding: 1rem 0.5rem;
}

.sidebar.collapsed > div:nth-child(2) .flex {
  width: 100%;
}

/* Mobile Responsive Sidebar */
@media (max-width: 768px) {
  .sidebar {
    position: fixed;
    left: 0;
    top: 0;
    height: 100vh;
    z-index: 50;
    transform: translateX(-100%);
  }

  .sidebar.expanded {
    transform: translateX(0);
  }

  .sidebar.collapsed {
    transform: translateX(-100%);
  }

  body.sidebar-open {
    overflow: hidden;
  }
}

/* Tooltip */
.tooltip {
  position: absolute;
  background: #1f2937;
  color: white;
  padding: 0.5rem 1rem;
  border-radius: 0.375rem;
  font-size: 0.875rem;
  white-space: nowrap;
  z-index: 1000;
  pointer-events: none;
  opacity: 0;
  transition: opacity 0.2s;
}

.tooltip.show {
  opacity: 1;
}

/* Dialog styles */
.ui-dialog {
  border-radius: 0.5rem;
  box-shadow: 0 20px 25px -5px rgba(0, 0, 0, 0.1), 0 10px 10px -5px rgba(0, 0, 0, 0.04);
}

.ui-dialog-titlebar {
  background: #2563eb;
  color: white;
  border-radius: 0.5rem 0.5rem 0 0;
  padding: 1rem;
}

/* Multi-step form */
.form-step {
  display: none;
}

.form-step.active {
  display: block;
  animation: fadeIn 0.5s ease-in;
}

.step-indicator {
  @apply flex items-center justify-center w-10 h-10 rounded-full border-2 border-gray-300 bg-white text-gray-500 font-semibold;
}

.step-indicator.active {
  @apply border-blue-600 bg-blue-600 text-white;
}

.step-indicator.completed {
  @apply border-green-600 bg-green-600 text-white;
}

/* Animated Ticker */
.ticker-container {
  background: linear-gradient(90deg, #1e40af, #2563eb, #1e40af);
  color: white;
  padding: 1rem;
  overflow: hidden;
  border-radius: 0.5rem;
  box-shadow: 0 4px 6px rgba(0, 0, 0, 0.1);
  margin-top: 2rem;
}

.ticker-content {
  display: flex;
  animation: scroll-left 30s linear infinite;
  white-space: nowrap;
  gap: 4rem;
}

.ticker-item {
  display: inline-flex;
  align-items: center;
  font-weight: 500;
  min-width: fit-content;
  padding: 0.5rem 1rem;
  font-size: 1rem;
}

@keyframes scroll-left {
  0% {
    transform: translateX(100%);
  }
  100% {
    transform: translateX(-100%);
  }
}

/* Hover pause animation */
.ticker-container:hover .ticker-content {
  animation-play-state: paused;
}

@media (max-width: 640px) {
  .ticker-item {
    font-size: 0.875rem;
    gap: 2rem;
  }

  .ticker-content {
    animation: scroll-left 20s linear infinite;
  }
}

